#include<bits/stdc++.h>
using namespace std;
int c[11],fa[20010],siz[20010];
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
void merge(int x,int y)
{
    fa[find(x)]=find(y);
}
struct edge
{
    int u,v,w;
    bool operator<(const edge&b)const
    {
        return w<b.w;
    }
}e[2000010],e1[2000010];
int main()
{
    int n,m,k;
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d%d",&e[i].u,&e[i].v,&e[i].w);
    }
    sort(e+1,e+1+m);
    int tot=0;
    for(int i=1;i<=n;i++)
    {
        fa[i]=i;
        siz[i]=1;
    }
    for(int i=1;i<=m;i++)
    {
        int u=e[i].u,v=e[i].v,w=e[i].w;
        if(find(u)!=find(v))
        {
            merge(u,v);
            e1[++tot]=e[i];
        }
    }
    for(int i=1;i<=k;i++)
    {
        scanf("%d",&c[i]);
        for(int j=1;j<=n;j++)
        {
            int x;
            scanf("%d",&x);
            e1[++tot]=(edge){j,i+n,x};
        }
    }
    sort(e1+1,e1+1+tot);
    long long ans=LLONG_MAX;
    for(int i=0;i<(1<<k);i++)
    {
        long long sum=0;
        for(int j=1;j<=k;j++)
        {
            if(i&(1<<(j-1)))
            {
                sum+=c[j];
            }
        }
        for(int j=1;j<=n+k;j++)
        {
            fa[j]=j;
            siz[j]=1;
        }
        for(int j=1;j<=tot;j++)
        {
            int u=e1[j].u,v=e1[j].v,w=e1[j].w;
            if(v<=n||(i&(1<<((v-n)-1))))
            {
                if(find(u)!=find(v))
                {
                    merge(u,v);
                    sum+=w;
                }
            }
        }
        ans=min(ans,sum);
    }
    printf("%lld",ans);
    return 0;
}
